    public override object parseOrder(object order, object market = null)
    {
        //
        // fetchOpenOrders
        //   [
        //     {
        //       "order_id": 315979358,
        //       "client_order_id": "add9a4b5-c7f7-4124-b57f-86982d86d479",
        //       "symbol": "ASTER",
        //       "side": "ask",
        //       "price": "1.836",
        //       "initial_amount": "85.33",
        //       "filled_amount": "0",
        //       "cancelled_amount": "0",
        //       "stop_price": null,
        //       "order_type": "limit",
        //       "stop_parent_order_id": null,
        //       "reduce_only": false,
        //       "created_at": 1759224706737,
        //       "updated_at": 1759224706737
        //     }
        //   ],
        //
        // fetchOrders
        //  [
        //     {
        //       "order_id": 315992721,
        //       "client_order_id": "ade",
        //       "symbol": "XPL",
        //       "side": "ask",
        //       "initial_price": "1.0865",
        //       "average_filled_price": "0",
        //       "amount": "984",
        //       "filled_amount": "0",
        //       "order_status": "open",
        //       "order_type": "limit",
        //       "stop_price": null,
        //       "stop_parent_order_id": null,
        //       "reduce_only": false,
        //       "reason": null,
        //       "created_at": 1759224893638,
        //       "updated_at": 1759224893638
        //     },
        //  ]
        //
        // fetchOrder
        //     {
        //       "history_id": 641452639,
        //       "order_id": 315992721,
        //       "client_order_id": "ade1aa6...",
        //       "symbol": "XPL",
        //       "side": "ask",
        //       "price": "1.0865",
        //       "initial_amount": "984",
        //       "filled_amount": "0",
        //       "cancelled_amount": "984",
        //       "event_type": "cancel",
        //       "order_type": "limit",
        //       "order_status": "cancelled",
        //       "stop_price": null,
        //       "stop_parent_order_id": null,
        //       "reduce_only": false,
        //       "created_at": 1759224895038
        //     }
        //
        // websocket watchOrders
        //     {
        //       "i": 1559665358,
        //       "I": null,
        //       "u": "BrZp5bidJ3WUvceSq7X78bhjTfZXeezzGvGEV4hAYKTa",
        //       "s": "BTC",
        //       "d": "bid",
        //       "p": "89501",
        //       "ip": "89501",
        //       "lp": "89501",
        //       "a": "0.00012",
        //       "f": "0.00012",
        //       "oe": "fulfill_limit",
        //       "os": "filled",
        //       "ot": "limit",
        //       "sp": null,
        //       "si": null,
        //       "r": false,
        //       "ct": 1765017049008,
        //       "ut": 1765017219639,
        //       "li": 1559696133
        //     }
        //
        object marketId = this.safeString2(order, "symbol", "s");
        object symbol = null;
        if (isTrue(!isEqual(symbol, null)))
        {
            market = this.safeMarket(marketId, market);
            symbol = getValue(market, "symbol");
        }
        object timestamp = this.safeInteger2(order, "created_at", "ct");
        object status = this.safeString2(order, "order_status", "os", "open"); // open if method is fetchOpenOrders
        object side = this.safeString(order, "side", "d");
        if (isTrue(!isEqual(side, null)))
        {
            side = ((bool) isTrue((isEqual(side, "bid")))) ? "buy" : "sell";
        }
        object totalAmount = this.safeString2(order, "initial_amount", "a");
        object filledAmount = this.safeString2(order, "filled_amount", "f");
        object remaining = Precise.stringSub(totalAmount, filledAmount);
        return this.safeOrder(new Dictionary<string, object>() {
            { "info", order },
            { "id", this.safeString2(order, "order_id", "i") },
            { "clientOrderId", this.safeString2(order, "client_order_id", "I") },
            { "timestamp", timestamp },
            { "datetime", this.iso8601(timestamp) },
            { "lastTradeTimestamp", null },
            { "lastUpdateTimestamp", this.safeInteger2(order, "updated_at", "ut") },
            { "symbol", symbol },
            { "type", this.parseOrderType(this.safeStringLower2(order, "order_type", "ot")) },
            { "timeInForce", null },
            { "postOnly", null },
            { "reduceOnly", this.safeBool2(order, "reduce_only", "r") },
            { "side", side },
            { "price", this.safeString2(order, "price", "lp") },
            { "triggerPrice", this.safeNumber2(order, "stop_price", "sp") },
            { "amount", totalAmount },
            { "cost", null },
            { "average", this.safeString2(order, "average_filled_price", "p") },
            { "filled", filledAmount },
            { "remaining", remaining },
            { "status", this.parseOrderStatus(status) },
            { "fee", null },
            { "trades", null },
        }, market);
    }

